// CalculateDiscount executes a JavaScript discount rule script in a Goja VM and returns the discount amount.
// The script can either:
//   - return a number directly, OR
//   - define a function `calculateDiscount(order)` that returns a number.
//
// The `order` object is provided as a global variable `order`. For backward compatibility,
// top-level fields of `order` are also injected as globals (e.g., order.total -> global `total`).
//
// Execution is time-bounded to prevent infinite loops / DoS.
func CalculateDiscount(script string, order map[string]interface{}) (float64, error) {
	const execTimeout = 200 * time.Millisecond

	vm := goja.New()

	// Provide the order as a single object.
	if err := vm.Set("order", order); err != nil {
		return 0, fmt.Errorf("failed to set order: %w", err)
	}

	// Backward compatibility: inject top-level fields as globals.
	for key, value := range order {
		if err := vm.Set(key, value); err != nil {
			return 0, fmt.Errorf("failed to set global %q: %w", key, err)
		}
	}

	// Time-bounded execution to prevent infinite loops.
	ctx, cancel := context.WithTimeout(context.Background(), execTimeout)
	defer cancel()
	go func() {
		<-ctx.Done()
		vm.Interrupt("timeout")
	}()

	// Execute the script (may define functions and/or return a value).
	result, err := vm.RunString(script)
	if err != nil {
		var ie *goja.InterruptedError
		if errors.As(err, &ie) || ctx.Err() == context.DeadlineExceeded {
			return 0, fmt.Errorf("script execution timeout")
		}
		return 0, fmt.Errorf("script execution error: %w", err)
	}

	// If script returned undefined, try calling calculateDiscount(order).
	if goja.IsUndefined(result) {
		fnVal := vm.Get("calculateDiscount")
		fn, ok := goja.AssertFunction(fnVal)
		if !ok {
			return 0, errors.New("script must return a number or define function calculateDiscount(order)")
		}

		result, err = fn(goja.Undefined(), vm.ToValue(order))
		if err != nil {
			var ie *goja.InterruptedError
			if errors.As(err, &ie) || ctx.Err() == context.DeadlineExceeded {
				return 0, fmt.Errorf("script execution timeout")
			}
			return 0, fmt.Errorf("calculateDiscount(order) error: %w", err)
		}
	}

	if goja.IsNull(result) || goja.IsUndefined(result) {
		return 0, errors.New("script returned null/undefined; must return a number")
	}

	num := result.ToNumber()
	if goja.IsNaN(num) {
		return 0, fmt.Errorf("script must return a finite number, got NaN")
	}

	discount := num.ToFloat()
	if math.IsNaN(discount) || math.IsInf(discount, 0) {
		return 0, fmt.Errorf("script must return a finite number, got %v", discount)
	}

	return discount, nil
}

func main() {
	// Example usage:
	script := `
		function calculateDiscount(order) {
			if (order.membership === "gold" && order.total >= 100) return order.total * 0.15;
			if (order.total >= 100) return order.total * 0.10;
			return 0;
		}
	`
	order := map[string]interface{}{
		"total":      120.0,
		"membership": "gold",
	}

	discount, err := CalculateDiscount(script, order)
	if err != nil {
		panic(err)
	}
	fmt.Println("discount:", discount)
